// Canonical types for the listing adapter layer.
// These map to the tables created in 20260518_000001_listings_canonical.sql.

export type ListingStatusCanonical =
  | 'active'
  | 'paused'
  | 'closed'
  | 'deleted'
  | 'under_review';

export type LogisticTypeCanonical =
  | 'full'
  | 'flex'
  | 'shopee_xpress'
  | 'envios'
  | 'correios'
  | 'agencia'
  | 'retire'
  | 'custom'
  | 'unknown';

export type QualityLevelCanonical =
  | 'excellent'
  | 'good'
  | 'medium'
  | 'low'
  | 'incomplete'
  | 'unknown';

// ---------------------------------------------------------------------------
// Canonical sub-objects (mirror DB columns)
// ---------------------------------------------------------------------------

export interface CanonicalListing {
  marketplace_name: string;
  marketplace_item_id: string;

  title: string;
  sku: string | null;
  category_id: string | null;
  category_path: string | null;
  permalink: string | null;
  thumbnail_url: string | null;
  has_variations: boolean;
  condition: 'new' | 'used' | 'refurbished' | null;

  status: ListingStatusCanonical;
  status_raw: string;
  sub_status: string[];
  pause_reason: string | null;

  price: number | null;
  original_price: number | null;
  promo_price: number | null;
  currency: string;

  available_quantity: number;
  sold_quantity: number;

  listing_type_id: string | null;
  catalog_listing: boolean | null;
  catalog_product_id: string | null;

  marketplace_created_at: string | null;
  marketplace_updated_at: string | null;
}

export interface CanonicalVariation {
  variation_id: string;
  sku: string | null;
  price: number | null;
  original_price: number | null;
  promo_price: number | null;
  available_quantity: number;
  sold_quantity: number;
  image_url: string | null;
  attributes: Array<{
    id: string;
    name: string;
    value_id?: string;
    value_name?: string;
  }>;
  primary_for_listing: boolean;
}

export interface CanonicalPicture {
  external_picture_id: string | null;
  url: string;
  secure_url: string | null;
  position: number;
  is_video: boolean;
  video_url: string | null;
  // When set, this picture belongs to a variation (matched by variation_id string)
  variation_id: string | null;
}

export interface CanonicalAttribute {
  attribute_id: string;
  attribute_name: string | null;
  value_id: string | null;
  value_name: string | null;
  value_struct: Record<string, unknown> | null;
  is_required: boolean | null;
  is_variation_attr: boolean | null;
}

export interface CanonicalShipping {
  logistic_type: LogisticTypeCanonical;
  logistic_types: LogisticTypeCanonical[];
  shipping_mode: string | null;
  free_shipping: boolean;
  mandatory_free_shipping: boolean;
  local_pick_up: boolean;
  package_length_cm: number | null;
  package_width_cm: number | null;
  package_height_cm: number | null;
  package_weight_g: number | null;
}

export interface CanonicalMetrics {
  visits_total: number;
  visits_last_30_days: number;
  impressions: number | null;
  sales_total: number;
  sales_last_30_days: number | null;
  conversion_rate: number;
  likes_total: number;
  comments_total: number;
  rating_average: number | null;
  reviews_count: number;
}

export interface CanonicalQuality {
  quality_score: number | null;
  quality_level: QualityLevelCanonical;
  missing_attributes: string[];
  unfinished_tasks: unknown[];
}

export interface CanonicalFees {
  currency: string;
  commission_amount: number | null;
  commission_percentage: number | null;
  commission_fixed_fee: number | null;
  listing_fee_amount: number | null;
  shipping_subsidy: number | null;
  total_fees_estimated: number | null;
  source_payload_version: number | null;
}

// ---------------------------------------------------------------------------
// Full normalised listing returned by each adapter
// ---------------------------------------------------------------------------

export interface NormalizedListing {
  listing: CanonicalListing;
  variations: CanonicalVariation[];
  pictures: CanonicalPicture[];
  attributes: CanonicalAttribute[];
  shipping: CanonicalShipping;
  metrics: CanonicalMetrics;
  quality: CanonicalQuality;
  fees: CanonicalFees;
}

/** Cached row from marketplace_provider_fee_rules (category commission). */
export interface ProviderFeeRuleSnapshot {
  commission_percentage?: number | null;
  commission_fixed_fee?: number | null;
  listing_fee_amount?: number | null;
  currency?: string | null;
  source?: string | null;
}

/** Optional rows from legacy tables + fee enrichment (all channels). */
export interface AdapterNormalizeExtra {
  metricsRow?: Record<string, unknown> | null;
  listingPricesRow?: Record<string, unknown> | null;
  qualityRow?: Record<string, unknown> | null;
  packageDims?: Record<string, unknown> | null;
  feeRule?: ProviderFeeRuleSnapshot | null;
  observedAvgCommissionAmount?: number | null;
  observedAvgCommissionPercentage?: number | null;
}

export interface AdapterContext {
  organizationId: string;
  integrationId?: string | null;
  payloadVersion?: number;
  extra?: AdapterNormalizeExtra;
}

export interface ListingAdapter {
  readonly channel: 'mercado-livre' | 'shopee';
  normalize(payload: unknown, ctx: AdapterContext): NormalizedListing;
}

// Writes a NormalizedListing (from any adapter) into the canonical tables
// using UPSERT operations. All writes use the service-role client to bypass RLS.

import type { NormalizedListing } from './types.ts';

// Supabase client interface subset (compatible with @supabase/supabase-js admin client)
interface SupabaseClient {
  // deno-lint-ignore no-explicit-any
  from: (table: string) => any;
}

export interface UpsertContext {
  organizationsId: string;
  integrationId?: string | null;
}

export async function upsertCanonicalListing(
  supabase: SupabaseClient,
  normalized: NormalizedListing,
  ctx: UpsertContext,
): Promise<{ listingId: string; error: Error | null }> {
  const { listing, variations, pictures, attributes, shipping, metrics, quality, fees } =
    normalized;

  // -------------------------------------------------------------------------
  // 1. Upsert core listing row → get canonical id
  // -------------------------------------------------------------------------
  const { data: listingRow, error: listingErr } = await supabase
    .from('marketplace_listings')
    .upsert(
      {
        organizations_id: ctx.organizationsId,
        integration_id: ctx.integrationId ?? null,
        marketplace_name: listing.marketplace_name,
        marketplace_item_id: listing.marketplace_item_id,
        title: listing.title,
        sku: listing.sku,
        category_id: listing.category_id,
        category_path: listing.category_path,
        permalink: listing.permalink,
        thumbnail_url: listing.thumbnail_url,
        has_variations: listing.has_variations,
        condition: listing.condition,
        status: listing.status,
        status_raw: listing.status_raw,
        sub_status: listing.sub_status,
        pause_reason: listing.pause_reason,
        price: listing.price,
        original_price: listing.original_price,
        promo_price: listing.promo_price,
        currency: listing.currency,
        available_quantity: listing.available_quantity,
        sold_quantity: listing.sold_quantity,
        listing_type_id: listing.listing_type_id,
        catalog_listing: listing.catalog_listing,
        catalog_product_id: listing.catalog_product_id,
        marketplace_created_at: listing.marketplace_created_at,
        marketplace_updated_at: listing.marketplace_updated_at,
        last_synced_at: new Date().toISOString(),
      },
      {
        onConflict: 'organizations_id,marketplace_name,marketplace_item_id',
        ignoreDuplicates: false,
      },
    )
    .select('id')
    .single();

  if (listingErr || !listingRow) {
    return { listingId: '', error: listingErr ?? new Error('Failed to upsert listing') };
  }

  const listingId: string = listingRow.id;

  // -------------------------------------------------------------------------
  // 2. Shipping
  // -------------------------------------------------------------------------
  await supabase.from('marketplace_listing_shipping').upsert(
    {
      listing_id: listingId,
      organizations_id: ctx.organizationsId,
      marketplace_name: listing.marketplace_name,
      marketplace_item_id: listing.marketplace_item_id,
      logistic_type: shipping.logistic_type,
      logistic_types: shipping.logistic_types,
      shipping_mode: shipping.shipping_mode,
      free_shipping: shipping.free_shipping,
      mandatory_free_shipping: shipping.mandatory_free_shipping,
      local_pick_up: shipping.local_pick_up,
      package_length_cm: shipping.package_length_cm,
      package_width_cm: shipping.package_width_cm,
      package_height_cm: shipping.package_height_cm,
      package_weight_g: shipping.package_weight_g,
      last_synced_at: new Date().toISOString(),
    },
    { onConflict: 'listing_id', ignoreDuplicates: false },
  );

  // -------------------------------------------------------------------------
  // 3. Metrics
  // -------------------------------------------------------------------------
  await supabase.from('marketplace_listing_metrics').upsert(
    {
      listing_id: listingId,
      organizations_id: ctx.organizationsId,
      marketplace_name: listing.marketplace_name,
      marketplace_item_id: listing.marketplace_item_id,
      visits_total: metrics.visits_total,
      visits_last_30_days: metrics.visits_last_30_days,
      impressions: metrics.impressions,
      sales_total: metrics.sales_total,
      sales_last_30_days: metrics.sales_last_30_days,
      conversion_rate: metrics.conversion_rate,
      likes_total: metrics.likes_total,
      comments_total: metrics.comments_total,
      rating_average: metrics.rating_average,
      reviews_count: metrics.reviews_count,
      last_synced_at: new Date().toISOString(),
    },
    { onConflict: 'listing_id', ignoreDuplicates: false },
  );

  // -------------------------------------------------------------------------
  // 4. Quality
  // -------------------------------------------------------------------------
  await supabase.from('marketplace_listing_quality').upsert(
    {
      listing_id: listingId,
      organizations_id: ctx.organizationsId,
      marketplace_name: listing.marketplace_name,
      marketplace_item_id: listing.marketplace_item_id,
      quality_score: quality.quality_score,
      quality_level: quality.quality_level,
      missing_attributes: quality.missing_attributes,
      unfinished_tasks: quality.unfinished_tasks,
      last_synced_at: new Date().toISOString(),
    },
    { onConflict: 'listing_id', ignoreDuplicates: false },
  );

  // -------------------------------------------------------------------------
  // 5. Fees
  // -------------------------------------------------------------------------
  await supabase.from('marketplace_listing_fees').upsert(
    {
      listing_id: listingId,
      organizations_id: ctx.organizationsId,
      marketplace_name: listing.marketplace_name,
      marketplace_item_id: listing.marketplace_item_id,
      currency: fees.currency,
      commission_amount: fees.commission_amount,
      commission_percentage: fees.commission_percentage,
      commission_fixed_fee: fees.commission_fixed_fee,
      listing_fee_amount: fees.listing_fee_amount,
      shipping_subsidy: fees.shipping_subsidy,
      total_fees_estimated: fees.total_fees_estimated,
      source_payload_version: fees.source_payload_version,
      last_synced_at: new Date().toISOString(),
    },
    { onConflict: 'listing_id', ignoreDuplicates: false },
  );

  // -------------------------------------------------------------------------
  // 6. Variations (delete-then-insert to handle removals cleanly)
  // -------------------------------------------------------------------------
  if (variations.length > 0) {
    // Delete stale variations not in current payload
    const currentVariationIds = variations.map((v) => v.variation_id);
    await supabase
      .from('marketplace_listing_variations')
      .delete()
      .eq('listing_id', listingId)
      .not('variation_id', 'in', `(${currentVariationIds.map((id) => `"${id}"`).join(',')})`);

    await supabase.from('marketplace_listing_variations').upsert(
      variations.map((v) => ({
        listing_id: listingId,
        organizations_id: ctx.organizationsId,
        marketplace_name: listing.marketplace_name,
        marketplace_item_id: listing.marketplace_item_id,
        variation_id: v.variation_id,
        sku: v.sku,
        price: v.price,
        original_price: v.original_price,
        promo_price: v.promo_price,
        available_quantity: v.available_quantity,
        sold_quantity: v.sold_quantity,
        image_url: v.image_url,
        attributes: v.attributes,
        primary_for_listing: v.primary_for_listing,
        last_synced_at: new Date().toISOString(),
      })),
      {
        onConflict: 'organizations_id,marketplace_name,marketplace_item_id,variation_id',
        ignoreDuplicates: false,
      },
    );
  }

  // -------------------------------------------------------------------------
  // 7. Pictures (replace all to keep positions fresh)
  // -------------------------------------------------------------------------
  if (pictures.length > 0) {
    await supabase
      .from('marketplace_listing_pictures')
      .delete()
      .eq('listing_id', listingId)
      .is('variation_id', null);  // only replace listing-level pictures

    await supabase.from('marketplace_listing_pictures').insert(
      pictures
        .filter((p) => !p.variation_id)
        .map((p) => ({
          listing_id: listingId,
          variation_id: null,
          organizations_id: ctx.organizationsId,
          marketplace_name: listing.marketplace_name,
          marketplace_item_id: listing.marketplace_item_id,
          external_picture_id: p.external_picture_id,
          url: p.url,
          secure_url: p.secure_url,
          position: p.position,
          is_video: p.is_video,
          video_url: p.video_url,
        })),
    );
  }

  // -------------------------------------------------------------------------
  // 8. Attributes (upsert by listing_id + attribute_id)
  // -------------------------------------------------------------------------
  if (attributes.length > 0) {
    await supabase.from('marketplace_listing_attributes').upsert(
      attributes.map((a) => ({
        listing_id: listingId,
        organizations_id: ctx.organizationsId,
        marketplace_name: listing.marketplace_name,
        marketplace_item_id: listing.marketplace_item_id,
        attribute_id: a.attribute_id,
        attribute_name: a.attribute_name,
        value_id: a.value_id,
        value_name: a.value_name,
        value_struct: a.value_struct,
        is_required: a.is_required,
        is_variation_attr: a.is_variation_attr,
      })),
      { onConflict: 'listing_id,attribute_id', ignoreDuplicates: false },
    );
  }

  return { listingId, error: null };
}

// deno-lint-ignore-file no-explicit-any
// listings-backfill — migrates existing data from marketplace_items_raw into
// the canonical tables by running the listing adapters on each stored payload.
//
// Request body:
//   {
//     organizationId: string,
//     marketplaceName?: string,   // filter to one channel; omit for both
//     pageSize?: number,          // default 100
//     offset?: number,            // default 0 (for pagination)
//     dryRun?: boolean            // default false
//   }
//
// This function is idempotent: all writes use UPSERT, so it is safe to re-run.

declare const Deno: any;

import { jsonResponse, handleOptions } from "../_shared/adapters/infra/http-utils.ts";
import { createAdminClient } from "../_shared/adapters/infra/supabase-client.ts";
import { syncCanonicalFromPayload } from "../_shared/listing-adapters/syncCanonicalFromPayload.ts";
import { fetchMlSupplementary, isMercadoLivreChannel } from "../_shared/listing-adapters/reconcileCanonical.ts";
import type { AdapterNormalizeExtra } from "../_shared/listing-adapters/types.ts";

Deno.serve(async (req: Request) => {
  if (req.method === "OPTIONS") return handleOptions();
  if (req.method !== "POST") return jsonResponse({ error: "Method not allowed" }, 405);

  const SUPABASE_URL = Deno.env.get("SUPABASE_URL");
  const SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

  if (!SUPABASE_URL || !SERVICE_ROLE_KEY) {
    return jsonResponse({ error: "Missing service configuration" }, 500);
  }

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return jsonResponse({ error: "Invalid JSON body" }, 400);
  }

  const organizationId = String(body.organizationId ?? '');
  const marketplaceName = body.marketplaceName ? String(body.marketplaceName) : null;
  const pageSize = Math.min(Number(body.pageSize ?? 100), 500);
  const offset = Number(body.offset ?? 0);
  const dryRun = body.dryRun === true;

  if (!organizationId) {
    return jsonResponse({ error: "organizationId is required" }, 400);
  }

  const supabase = createAdminClient();

  // -------------------------------------------------------------------------
  // Create audit row
  // -------------------------------------------------------------------------
  const { data: jobRow } = await supabase
    .from("marketplace_listing_sync_jobs" as any)
    .insert({
      organizations_id: organizationId,
      marketplace_name: marketplaceName ?? 'all',
      marketplace_item_id: '*',
      scope: 'backfill',
      status: 'running',
      started_at: new Date().toISOString(),
    })
    .select("id")
    .single();

  const jobId: string | null = jobRow?.id ?? null;
  const startedAt = Date.now();

  const updateJob = async (status: string, errorMsg?: string, extra?: Record<string, unknown>) => {
    if (!jobId) return;
    const finishedAt = new Date();
    await supabase
      .from("marketplace_listing_sync_jobs" as any)
      .update({
        status,
        error_message: errorMsg ?? null,
        finished_at: finishedAt.toISOString(),
        duration_ms: Date.now() - startedAt,
        ...extra,
      })
      .eq("id", jobId);
  };

  try {
    // -------------------------------------------------------------------------
    // Fetch a page of raw items
    // -------------------------------------------------------------------------
    let query = supabase
      .from("marketplace_items_raw" as any)
      .select("id, marketplace_item_id, marketplace_name, integration_id, data, updated_at")
      .eq("organizations_id", organizationId)
      .order("id", { ascending: true })
      .range(offset, offset + pageSize - 1);

    if (marketplaceName) {
      query = query.eq("marketplace_name", marketplaceName);
    }

    const { data: rawItems, error: fetchErr } = await query;

    if (fetchErr) {
      await updateJob('error', fetchErr.message);
      return jsonResponse({ error: fetchErr.message }, 500);
    }

    const items: any[] = rawItems ?? [];
    const results = { processed: 0, skipped: 0, errors: [] as string[] };

    const mlItemIds = items
      .filter((it) => isMercadoLivreChannel(String(it.marketplace_name ?? it.marketplace ?? '')))
      .map((it) => String(it.marketplace_item_id))
      .filter(Boolean);

    const metricsByItemId = new Map<string, Record<string, unknown>>();
    const pricesByItemId = new Map<string, Record<string, unknown>>();

    if (mlItemIds.length > 0) {
      const [metricsRes, pricesRes] = await Promise.all([
        supabase
          .from('marketplace_metrics')
          .select('*')
          .eq('organizations_id', organizationId)
          .eq('marketplace_name', 'Mercado Livre')
          .in('marketplace_item_id', mlItemIds),
        supabase
          .from('marketplace_item_prices')
          .select('*')
          .eq('organizations_id', organizationId)
          .eq('marketplace_name', 'Mercado Livre')
          .in('marketplace_item_id', mlItemIds),
      ]);
      for (const row of metricsRes.data ?? []) {
        metricsByItemId.set(String(row.marketplace_item_id), row);
      }
      for (const row of pricesRes.data ?? []) {
        pricesByItemId.set(String(row.marketplace_item_id), row);
      }
    }

    for (const item of items) {
      const mktName: string =
        item.marketplace_name ?? item.marketplace ?? '';

      if (!mktName) {
        results.skipped++;
        continue;
      }

      try {
        const itemId = String(item.marketplace_item_id);
        let mlExtra: AdapterNormalizeExtra | undefined;
        if (isMercadoLivreChannel(mktName)) {
          const metricsRow = metricsByItemId.get(itemId) ?? null;
          mlExtra = {
            metricsRow,
            listingPricesRow: pricesByItemId.get(itemId) ?? null,
            qualityRow: metricsRow,
          };
        }

        if (!dryRun) {
          const syncResult = await syncCanonicalFromPayload(supabase as any, {
            organizationId,
            integrationId: item.integration_id ?? null,
            marketplaceName: mktName,
            marketplaceItemId: itemId,
            payload: item,
            payloadSource: 'backfill',
            mlExtra,
            force: true,
          });

          if (!syncResult.ok) {
            results.errors.push(`${itemId}: ${syncResult.error ?? 'sync failed'}`);
            continue;
          }
        }

        results.processed++;
      } catch (err: any) {
        results.errors.push(`${item.marketplace_item_id}: ${err?.message ?? String(err)}`);
      }
    }

    const summary = {
      total: items.length,
      processed: results.processed,
      skipped: results.skipped,
      errors: results.errors.length,
      errorDetails: results.errors.slice(0, 20),
      dryRun,
      offset,
      pageSize,
      hasMore: items.length === pageSize,
    };

    const status = results.errors.length === 0 ? 'success' : 'success_with_errors';
    await updateJob(status, results.errors.length > 0 ? results.errors.join('; ').slice(0, 500) : undefined);

    return jsonResponse({ ok: true, jobId, ...summary });
  } catch (err: any) {
    const msg = err?.message ?? String(err);
    await updateJob('error', msg);
    return jsonResponse({ error: msg }, 500);
  }
});
